import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface HeartRateData {
  widget: {
    id: string;
    app: string;
    version: string;
  };
  data: {
    currentBPM: number;
    restingRate: number;
    trend24h: number[];
  };
  meta: {
    theme: string;
    dataMode: string;
    layout: string;
    primaryColor: string;
    accentColor: string;
    chartTypes: string[];
  };
}

export default function Widget() {
  const heartRateData = response.data as HeartRateData;
  const { currentBPM, restingRate, trend24h } = heartRateData.data;
  const { primaryColor, accentColor } = heartRateData.meta;
  const isAboveResting = currentBPM > restingRate;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#121212' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: accentColor }}>
              Heart Rate Monitor
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ color: primaryColor, mt: 0.5 }}>
              {currentBPM} BPM
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isAboveResting ? <TrendingUp sx={{ fontSize: 20, color: primaryColor }} /> : <TrendingDown sx={{ fontSize: 20, color: primaryColor }} />}
              <Typography variant="body2" sx={{ color: isAboveResting ? primaryColor : accentColor }}>
                {isAboveResting ? 'Above' : 'Below'} Resting Rate
              </Typography>
            </Stack>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: trend24h,
                color: primaryColor,
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: trend24h.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
